import{_ as l,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const u=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI开发工具/AReaL-AI开发工具.md","filePath":"github汇总/AI开发工具/AReaL-AI开发工具.md"}'),h={name:"github汇总/AI开发工具/AReaL-AI开发工具.md"};function t(n,a,o,s,d,c){return e(),i("div",null,a[0]||(a[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>AReaL</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>inclusionAI</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>AI开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><ul><li>AI Agent使用后能力无法提升</li><li>缺少智能体边用边训的训练框架</li><li>难以自定义强化学习工作流程</li><li>不同Agent框架之间兼容性差</li></ul><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>智能体强化学习训练框架</li><li>为OpenClaw等Agent提供边用边训能力</li><li>只需一个文件即可自定义多轮rollout工作流程</li><li>可顺畅整合其他智能体工具框架</li><li>兼容性强，可兼容任意Agent</li><li>提供灵活性、可扩展性和兼容性三大亮点</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>为Agent提供边用边训能力，让AI不断进化</li><li>只需一个文件即可自定义工作流程</li><li>可整合其他智能体工具框架</li><li>兼容性强，支持任意Agent</li><li>配有相关学术论文</li><li>开源v1.0版本</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/inclusionAI/AReaL" target="_blank" rel="noreferrer">https://github.com/inclusionAI/AReaL</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>本教程适用于想要使用AReaL训练AI Agent的开发者，支持Windows、Linux和MacOS系统。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><h3 id="_1-python版本检查" tabindex="-1">1. Python版本检查 <a class="header-anchor" href="#_1-python版本检查" aria-label="Permalink to “1. Python版本检查”">​</a></h3><ul><li>步骤目标：确认Python版本满足要求</li><li>执行位置：本机终端</li><li>完整命令：<code>python --version</code></li><li>成功标志：显示Python 3.8或更高版本</li><li>失败处理：请安装或升级Python至3.8+版本</li></ul><h3 id="_2-git检查" tabindex="-1">2. Git检查 <a class="header-anchor" href="#_2-git检查" aria-label="Permalink to “2. Git检查”">​</a></h3><ul><li>步骤目标：确认Git已安装</li><li>执行位置：本机终端</li><li>完整命令：<code>git --version</code></li><li>成功标志：显示Git版本信息</li><li>失败处理：请安装Git</li></ul><h3 id="_3-网络访问检查" tabindex="-1">3. 网络访问检查 <a class="header-anchor" href="#_3-网络访问检查" aria-label="Permalink to “3. 网络访问检查”">​</a></h3><ul><li>步骤目标：确认可以访问GitHub</li><li>执行位置：本机浏览器</li><li>检查方法：访问<a href="https://github.com/inclusionAI/AReaL" target="_blank" rel="noreferrer">https://github.com/inclusionAI/AReaL</a></li><li>成功标志：可以正常访问项目页面</li><li>失败处理：请配置海外网络环境 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><h2 id="主路径-安装与使用" tabindex="-1">主路径：安装与使用 <a class="header-anchor" href="#主路径-安装与使用" aria-label="Permalink to “主路径：安装与使用”">​</a></h2><h3 id="步骤1-克隆项目仓库" tabindex="-1">步骤1：克隆项目仓库 <a class="header-anchor" href="#步骤1-克隆项目仓库" aria-label="Permalink to “步骤1：克隆项目仓库”">​</a></h3><ul><li>步骤目标：从GitHub克隆AReaL项目</li><li>执行位置：本机终端</li><li>完整命令：<code>git clone https://github.com/inclusionAI/AReaL.git</code></li><li>成功标志：项目克隆完成</li><li>失败处理：检查网络连接</li></ul><h3 id="步骤2-进入项目目录" tabindex="-1">步骤2：进入项目目录 <a class="header-anchor" href="#步骤2-进入项目目录" aria-label="Permalink to “步骤2：进入项目目录”">​</a></h3><ul><li>步骤目标：进入AReaL项目目录</li><li>执行位置：本机终端</li><li>完整命令：<code>cd AReaL</code></li><li>成功标志：当前目录变为AReaL</li><li>失败处理：确保克隆成功</li></ul><h3 id="步骤3-安装项目依赖" tabindex="-1">步骤3：安装项目依赖 <a class="header-anchor" href="#步骤3-安装项目依赖" aria-label="Permalink to “步骤3：安装项目依赖”">​</a></h3><ul><li>步骤目标：安装项目所需的所有依赖包</li><li>执行位置：项目目录终端</li><li>完整命令：<code>pip install -r requirements.txt</code></li><li>成功标志：依赖安装完成，无错误</li><li>失败处理：检查网络连接，或使用国内镜像源</li></ul><h3 id="步骤4-查看文档" tabindex="-1">步骤4：查看文档 <a class="header-anchor" href="#步骤4-查看文档" aria-label="Permalink to “步骤4：查看文档”">​</a></h3><ul><li>步骤目标：了解如何使用AReaL</li><li>执行位置：项目目录</li><li>完整命令：查看README和文档</li><li>成功标志：了解使用方法</li><li>失败处理：参考项目文档</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><h3 id="_1-运行示例" tabindex="-1">1. 运行示例 <a class="header-anchor" href="#_1-运行示例" aria-label="Permalink to “1. 运行示例”">​</a></h3><ul><li>测试方法：尝试运行项目提供的示例</li><li>预期返回：示例可以正常运行</li></ul><h3 id="_2-自定义工作流" tabindex="-1">2. 自定义工作流 <a class="header-anchor" href="#_2-自定义工作流" aria-label="Permalink to “2. 自定义工作流”">​</a></h3><ul><li>测试方法：尝试创建自定义的工作流程文件</li><li>预期返回：可以正常自定义</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><h3 id="现象1-python版本过低" tabindex="-1">现象1：Python版本过低 <a class="header-anchor" href="#现象1-python版本过低" aria-label="Permalink to “现象1：Python版本过低”">​</a></h3><ul><li>可能原因：Python版本不满足最低要求</li><li>解决步骤： <ol><li>检查当前Python版本：python --version</li><li>下载并安装Python 3.8或更高版本</li><li>重新打开终端并验证版本</li></ol></li></ul><h3 id="现象2-依赖安装失败" tabindex="-1">现象2：依赖安装失败 <a class="header-anchor" href="#现象2-依赖安装失败" aria-label="Permalink to “现象2：依赖安装失败”">​</a></h3><ul><li>可能原因：网络问题或pip镜像源访问受限</li><li>解决步骤： <ol><li>检查网络连接</li><li>配置国内pip镜像源：pip config set registry <a href="https://registry.npmmirror.com" target="_blank" rel="noreferrer">https://registry.npmmirror.com</a></li><li>重新运行pip install</li></ol></li></ul><h3 id="现象3-运行失败" tabindex="-1">现象3：运行失败 <a class="header-anchor" href="#现象3-运行失败" aria-label="Permalink to “现象3：运行失败”">​</a></h3><ul><li>可能原因：配置问题或缺少依赖</li><li>解决步骤： <ol><li>检查配置是否正确</li><li>确认所有依赖已安装</li><li>查看项目Issue页面是否有类似问题</li></ol></li></ul><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>基于公开可验证信息整理，完整教程请参考项目GitHub仓库的README文档。</p><p>更多详细文档请参考：</p><ul><li>GitHub仓库：<a href="https://github.com/inclusionAI/AReaL" target="_blank" rel="noreferrer">https://github.com/inclusionAI/AReaL</a> <a href="/网络环境.html">海外网络环境配置 →</a></li><li>相关论文：<a href="https://arxiv.org/abs/2505.24298" target="_blank" rel="noreferrer">https://arxiv.org/abs/2505.24298</a></li></ul>',51)]))}const p=l(h,[["render",t]]);export{u as __pageData,p as default};
